	prg.plFile.Rewrite()

	strcopy(prg.ascii04[:], " !\"#$%&'()*+,-./0123456789:;<=>?")

	strcopy(prg.ascii10[:], "@ABCDEFGHIJKLMNOPQRSTUVWXYZ[\\]^_")

	strcopy(prg.ascii14[:], "`abcdefghijklmnopqrstuvwxyz{|}~ ")

	strcopy(prg.mblString[:], "MBL")
	strcopy(prg.riString[:], "RI ")
	strcopy(prg.rceString[:], "RCE")

	prg.level = 0

	prg.charsOnLine = 0

	prg.perfect = true // innocent until proved guilty

	prg.boundaryChar = 256
	prg.bcharLabel = 077777

	prg.labelPtr = 0
	prg.labelTable[0].rr = 0 // a sentinel appears at the bottom

