// 30.

// tangle:pos tftopl.web:598:3:

// Here, in fact, are two procedures that output |dig[j-1]|$\,\ldots\,$|dig[0]|,
// given $j>0$.
func (prg *prg) outDigs(j int32) {
	for {
		j = j - 1
		prg.plFile.Write(prg.dig[j], knuth.WriteWidth(1))
		if j == 0 {
			break
		}
	}
}

func (prg *prg) printDigs(j int32) {
	for {
		j = j - 1
		prg.stdout.Write(prg.dig[j], knuth.WriteWidth(1))
		if j == 0 {
			break
		}
	}
}

// 31.

// tangle:pos tftopl.web:611:3:

// The |print_octal| procedure indicates how |print_digs| can be used.
// Since this procedure is used only to print character codes, it always
// produces three digits.
func (prg *prg) printOctal(c byte) { // prints octal value of |c|
	var (
		j /* 0..2 */ byte // index into |dig|
	)
	prg.stdout.Write("'") // an apostrophe indicates the octal notation
	for ii := int32(0); ii <= 2; ii++ {
		j = byte(ii)
		_ = j
		prg.dig[j] = byte(int32(c) % 8)
		c = byte(int32(c) / 8)
	}
	prg.printDigs(3)
}

// 34.

// tangle:pos tftopl.web:634:3:

// Three simple procedures suffice to produce the desired structure in the
// output.
func (prg *prg) outLn() { // finishes one line, indents the next
	var (
		l /* 0..5 */ byte
	)
	prg.plFile.Writeln()
	for ii := int32(1); ii <= int32(prg.level); ii++ {
		l = byte(ii)
		_ = l
		prg.plFile.Write("   ")
	}
}

func (prg *prg) left() {
	prg.level = byte(int32(prg.level) + 1)
	prg.plFile.Write("(")
}

