// tangle:pos tftopl.web:702:3:

// The property value may be a character, which is output in octal
// unless it is a letter or a digit. This procedure is the only place
// where a lowercase letter will be output to the \.[PL] file.
// \xref[system dependencies]
func (prg *prg) outChar(c byte) {
	if int32(prg.fontType) > vanilla {
		prg.tfm[0+1000] = c
		prg.outOctal(index(0), index(1))
	} else if int32(c) >= '0' && int32(c) <= '9' {
		prg.plFile.Write(" C ", int32(c)-'0', knuth.WriteWidth(1))
	} else if int32(c) >= 'A' && int32(c) <= 'Z' {
		prg.plFile.Write(" C ", string(rune(prg.ascii10[int32(c)-'A'+2-1])))
	} else if int32(c) >= 'a' && int32(c) <= 'z' {
		prg.plFile.Write(" C ", string(rune(prg.ascii14[int32(c)-'a'+2-1])))
	} else {
		prg.tfm[0+1000] = c
		prg.outOctal(index(0), index(1))
	}
}

