// The property value might be a “face” byte, which is output in the
// curious code mentioned earlier, provided that it is less than 18.
func (prg *prg) outFace(k index) { // outputs a |face|
	var (
		s/* 0..1 */ byte // the slope
		b/* 0..8 */ byte // the weight and expansion
	)
	if int32(prg.tfm[k+1000]) >= 18 {
		prg.outOctal(k, index(1))
	} else {
		prg.plFile.Write(" F ") // specify face-code format
		s = byte(int32(prg.tfm[k+1000]) % 2)
		b = byte(int32(prg.tfm[k+1000]) / 2)
		prg.plFile.Write(string(rune(prg.mblString[1+int32(b)%3-1])))
		prg.plFile.Write(string(rune(prg.riString[1+int32(s)-1])))
		prg.plFile.Write(string(rune(prg.rceString[1+int32(b)/3-1])))
	}
}

