// tangle:pos tftopl.web:736:3:

// And finally, the value might be a |fix_word|, which is output in
// decimal notation with just enough decimal places for \.[PLtoTF]
// to recover every bit of the given |fix_word|.
//
// All of the numbers involved in the intermediate calculations of
// this procedure will be nonnegative and less than $10\cdot2^[24]$.
func (prg *prg) outFix(k index) { // outputs a |fix_word|
	var (
		a/* 0..07777 */ uint16       // accumulator for the integer part
		f                      int32 // accumulator for the fraction part
		j/* 0..12 */ byte            // index into |dig|
		delta                  int32 // amount if allowable inaccuracy
	)
	prg.plFile.Write(" R ") // specify real format
	a = uint16(int32(prg.tfm[k+1000])*16 + int32(prg.tfm[int32(k)+1+1000])/16)
	f = (int32(prg.tfm[int32(k)+1+1000])%16*0400+int32(prg.tfm[int32(k)+2+1000]))*0400 + int32(prg.tfm[int32(k)+3+1000])
	if int32(a) > 03777 {
		prg.plFile.Write("-")
		a = uint16(010000 - int32(a))
		if f > 0 {
			f = 04000000 - f
			a = uint16(int32(a) - 1)
		}
	}

	// Output the integer part, |a|, in decimal notation
	{
		j = 0
		for {
			prg.dig[j] = byte(int32(a) % 10)
			a = uint16(int32(a) / 10)
			j = byte(int32(j) + 1)
			if int32(a) == 0 {
				break
			}
		}
		prg.outDigs(int32(j))
	}

	// Output the fraction part, $|f|/2^[20]$, in decimal notation
	{
		prg.plFile.Write(".")
		f = 10*f + 5
		delta = 10
		for {
			if delta > 04000000 {
				f = f + 02000000 - delta/2
			}
			prg.plFile.Write(f/04000000, knuth.WriteWidth(1))
			f = 10 * (f % 04000000)
			delta = delta * 10
			if f <= delta {
				break
			}
		}
	}

}

