// Since we have to check two different [\mc BCPL] strings for validity,
// we might as well write a subroutine to make the check.
func (prg *prg) checkBcpl(k, l index) { // checks a string of length |<l|
	var (
		j index // runs through the string
		c byte  // character being checked
	)
	if int32(prg.tfm[k+1000]) >= int32(l) {
		{
			prg.perfect = false
			if int32(prg.charsOnLine) > 0 {
				prg.stdout.Writeln(" ")
			}
			prg.charsOnLine = 0
			prg.stdout.Writeln("Bad TFM file: ", "String is too long; I've shortened it drastically.")
		}
		// \xref[String is too long...]
		prg.tfm[k+1000] = 1
	}
	for ii := int32(k) + 1; ii <= int32(k)+int32(prg.tfm[k+1000]); ii++ {
		j = index(ii)
		_ = j
		c = prg.tfm[j+1000]
		if int32(c) == '(' || int32(c) == ')' {
			{
				prg.perfect = false
				if int32(prg.charsOnLine) > 0 {
					prg.stdout.Writeln(" ")
				}
				prg.charsOnLine = 0
				prg.stdout.Writeln("Bad TFM file: ", "Parenthesis in string has been changed to slash.")
			}
			// \xref[Parenthesis...changed to slash]
			prg.tfm[j+1000] = '/'
		} else if int32(c) < ' ' || int32(c) > '~' {
			{
				prg.perfect = false
				if int32(prg.charsOnLine) > 0 {
					prg.stdout.Writeln(" ")
				}
				prg.charsOnLine = 0
				prg.stdout.Writeln("Bad TFM file: ", "Nonstandard ASCII code has been blotted out.")
			}
			// \xref[Nonstandard ASCII code...]
			prg.tfm[j+1000] = '?'
		} else if int32(c) >= 'a' && int32(c) <= 'z' {
			prg.tfm[j+1000] = byte(int32(c) + 'A' - 'a')
		} // upper-casify letters
	}
}

