// tangle:pos tftopl.web:1497:3:

// Evaluation of $f(x,y)$ is handled by two mutually recursive procedures.
// Kind of a neat algorithm, generalizing a depth-first search.
func (prg *prg) f(h, x, y index) (r index) {
	switch prg.class[h] {
	case simple:
	case leftZ:
		prg.class[h] = byte(pending)
		prg.ligZ[h] = prg.eval(prg.ligZ[h], y)
		prg.class[h] = byte(simple)

	case rightZ:
		prg.class[h] = byte(pending)
		prg.ligZ[h] = prg.eval(x, prg.ligZ[h])
		prg.class[h] = byte(simple)

	case bothZ:
		prg.class[h] = byte(pending)
		prg.ligZ[h] = prg.eval(prg.eval(x, prg.ligZ[h]), y)
		prg.class[h] = byte(simple)

	case pending:
		prg.xLigCycle = x
		prg.yLigCycle = y
		prg.ligZ[h] = 257
		prg.class[h] = byte(simple)
		// the value 257 will break all cycles, since it's not in |hash|
	} // there are no other cases
	r = prg.ligZ[h]
	return r
}

